<script setup>
import { computed, onMounted, ref } from 'vue'
import AppDrawer from '../components/AppDrawer.vue'
import { api } from '../services/api'

const payments = ref([]), users = ref([]), loading = ref(true), error = ref(''), selected = ref(null), nextStatus = ref('pagado'), filter = ref('')
const states = { pagado: 'Pagado', reembolsado: 'Reembolsado', cancelado: 'Cancelado' }
const visible = computed(() => filter.value ? payments.value.filter((payment) => payment.estado === filter.value) : payments.value)
const totalPaid = computed(() => payments.value.filter((p) => p.estado === 'pagado').reduce((sum, p) => sum + Number(p.total), 0))
const userFor = (id) => users.value.find((user) => user.id === id)
const short = (prefix, id) => `#${prefix}-${String(id).slice(-4).toUpperCase()}`
const date = (value) => new Intl.DateTimeFormat('es-MX', { dateStyle: 'medium' }).format(new Date(value))
async function load() { loading.value = true; try { [payments.value, users.value] = await Promise.all([api.get('/pagos/'), api.get('/usuarios/')]) } catch (err) { error.value = err.message } finally { loading.value = false } }
function open(payment) { selected.value = payment; nextStatus.value = payment.estado }
async function save() { try { await api.patch(`/pagos/${selected.value.id}/`, { estado: nextStatus.value }); selected.value = null; await load() } catch (err) { error.value = err.message } }
onMounted(load)
</script>

<template><section class="admin-page"><header class="page-heading"><div><h1>Pagos</h1><p>Consulta y administra los pagos registrados en las compras.</p></div><select v-model="filter" class="compact-select"><option value="">Todos los estados</option><option v-for="(label, value) in states" :key="value" :value="value">{{ label }}</option></select></header><div class="metric-grid"><article class="metric"><span>Pagos registrados</span><strong>{{ payments.length }}</strong></article><article class="metric"><span>Total cobrado</span><strong>${{ totalPaid.toFixed(2) }}</strong></article><article class="metric warning"><span>Reembolsados</span><strong>{{ payments.filter(p => p.estado === 'reembolsado').length }}</strong></article><article class="metric danger"><span>Cancelados</span><strong>{{ payments.filter(p => p.estado === 'cancelado').length }}</strong></article></div><div v-if="error" class="feedback error">{{ error }}</div><div class="data-table-wrap"><table class="data-table"><thead><tr><th>Folio de pago</th><th>Pedido</th><th>Cliente</th><th>Fecha</th><th>Total</th><th>Estado</th><th>Acciones</th></tr></thead><tbody><tr v-if="loading"><td colspan="7">Cargando pagos...</td></tr><tr v-for="payment in visible" :key="payment.id"><td><strong class="folio">{{ short('PAG', payment.id) }}</strong></td><td>{{ short('PED', payment.pedido_id) }}</td><td>{{ userFor(payment.usuario_id)?.nombre || 'Cliente' }}</td><td>{{ date(payment.creado_en) }}</td><td><strong>${{ Number(payment.total).toFixed(2) }}</strong></td><td><span class="status-badge" :class="payment.estado">{{ states[payment.estado] }}</span></td><td><button class="table-action" @click="open(payment)">Ver detalle</button></td></tr></tbody></table></div><AppDrawer :open="Boolean(selected)" :title="selected ? `Pago ${short('PAG', selected.id)}` : 'Pago'" @close="selected = null"><div v-if="selected" class="drawer-stack"><div class="detail-grid"><div><span>Fecha</span><strong>{{ date(selected.creado_en) }}</strong></div><div><span>Estado actual</span><b class="status-badge" :class="selected.estado">{{ states[selected.estado] }}</b></div></div><section class="detail-section"><h3>Pedido relacionado</h3><strong class="folio">{{ short('PED', selected.pedido_id) }}</strong></section><section class="detail-section"><h3>Cliente</h3><strong>{{ userFor(selected.usuario_id)?.nombre }}</strong><p>{{ userFor(selected.usuario_id)?.correo }}</p></section><div class="payment-total"><span>Monto total</span><strong>${{ Number(selected.total).toFixed(2) }}</strong></div><div class="field"><label>Actualizar estado del pago</label><select v-model="nextStatus"><option v-for="(label, value) in states" :key="value" :value="value">{{ label }}</option></select></div><div class="notice">Cambiar el estado registra la situación administrativa del pago. No realiza movimientos bancarios.</div></div><template #footer><button class="button-secondary" @click="selected = null">Cerrar</button><button class="button-primary" @click="save">Guardar estado</button></template></AppDrawer></section></template>
